+
+/// F9: Diamond shape — join at top, race at bottom, two paths.
+/// No DedupRaceJoin pattern present.
+fn diamond_join_race() -> PlanFixture {
+    let mut dag = PlanDag::new();
+    let a = dag.leaf("a");
+    let b = dag.leaf("b");
+    let c = dag.leaf("c");
+    let race = dag.race(vec![b, c]);
