+        let mut idx = id.index();
+        let mut root = idx;
+        while self.parent[root].index() != root {
+            root = self.parent[root].index();
+        }
+
+        while self.parent[idx].index() != root {
+            let next = self.parent[idx].index();
+            self.parent[idx] = EClassId::new(root);
+            idx = next;
+        }
